#!/usr/bin/env bash
set -euo pipefail

# Freddy Fix It — Milestone Escrow installer.
# Big jobs (quote > $2,000) can be paid in 2-5 escrow-protected, fund-as-you-go
# stages. Small jobs (<= $2k) are untouched. DB + edge-function DEPLOYS are
# already LIVE (applied via Supabase MCP); this ships the FRONTEND plus committed
# copies of the edge-function source for version control.
# Resets to published origin/main first, so it is a full superset — running it
# delivers everything already live PLUS the milestone feature.

TARGET="$HOME/Desktop/freddy-fixit"
if [ ! -d "$TARGET/.git" ]; then echo "❌ $TARGET is not a git repo"; exit 1; fi
cd "$TARGET"
echo "→ Syncing to the published version (discards any half-applied local state)"
git fetch origin --quiet || true
git reset --hard origin/main --quiet
rm -f .github/workflows/typecheck.yml
echo "→ Writing files into $TARGET"

write_file() {  # write_file <destpath> ; base64 body on stdin
  local dest="$1"
  mkdir -p "$(dirname "$dest")"
  base64 --decode > "$dest"
}

echo "  • src/components/MilestonePanel.tsx"
